fn orc_ell(p: vec2f, c: vec2f, r: vec2f, ang: f32) -> f32 {
  let q = rotate(p - c, ang);
  return length(q / r) - 1.0;
}

// one phalaenopsis bloom, facing the viewer. bp: local coords · s: scale
fn orc_bloom(bp: vec2f, s: f32, flutter: f32, seed: f32) -> vec4f {
  var col = vec4f(0.0);
  let p = bp / s;
  // five petals: dorsal, two laterals (wide), two sepals (low)
  for (var i = 0; i < 5; i++) {
    let fi = f32(i);
    var ang = 0.0;
    var rad = vec2f(0.34, 0.62);
    var off = vec2f(0.0);
    if (i == 0) { ang = 0.0; off = vec2f(0.0, -0.52); rad = vec2f(0.30, 0.55); }         // dorsal
    else if (i == 1) { ang = 1.15; off = vec2f(-0.58, -0.02); rad = vec2f(0.62, 0.40); } // left wing
    else if (i == 2) { ang = -1.15; off = vec2f(0.58, -0.02); rad = vec2f(0.62, 0.40); } // right wing
    else if (i == 3) { ang = 0.55; off = vec2f(-0.30, 0.44); rad = vec2f(0.30, 0.46); }  // sepals
    else { ang = -0.55; off = vec2f(0.30, 0.44); rad = vec2f(0.30, 0.46); }
    let fl = flutter * (0.5 + 0.5 * sin(seed * 7.0 + fi * 2.4));
    let d = orc_ell(p, off * (1.0 + fl * 0.05), rad * (1.0 + fl * 0.06), ang + fl * 0.08);
    if (d < 0.0) {
      // petal body: near-white heart flushing magenta at the rim
      let rimm = clamp(-d * 2.2, 0.0, 1.0);
      var pc = mix(vec3f(0.98, 0.62, 0.86), vec3f(0.995, 0.94, 0.975), rimm);
      // radial veins, magenta, finer toward the edge
      let va = atan2(p.y - off.y, p.x - off.x);
      let vein = pow(abs(sin(va * 11.0 + seed * 3.0)), 24.0);
      pc = mix(pc, vec3f(0.86, 0.30, 0.62), vein * (1.0 - rimm) * 0.55);
      // edge translucency: light leaks through the thin rim
      pc += vec3f(0.10, 0.06, 0.09) * (1.0 - rimm) * 0.6;
      // soft top-left light
      pc *= 0.92 + 0.14 * clamp(-(p.x + p.y) * 0.4 + 0.5, 0.0, 1.0);
      col = vec4f(pc, 1.0);
    }
  }
  // the lip (labellum): deep magenta tongue with a gold throat
  let ld = orc_ell(p, vec2f(0.0, 0.16), vec2f(0.17, 0.24), 0.0);
  if (ld < 0.0) {
    var lc = mix(vec3f(0.72, 0.12, 0.38), vec3f(0.92, 0.30, 0.55), clamp(-ld * 3.0, 0.0, 1.0));
    lc = mix(lc, vec3f(0.98, 0.78, 0.25), smoothstep(0.10, 0.0, length(p - vec2f(0.0, 0.05))));
    // throat speckles
    let sp = hash21(floor(p * 40.0) + seed);
    lc = mix(lc, vec3f(0.55, 0.08, 0.28), step(0.82, sp) * 0.7);
    col = vec4f(lc, 1.0);
  }
  // the column: a small pale hood at the center
  let cd = orc_ell(p, vec2f(0.0, -0.04), vec2f(0.08, 0.11), 0.0);
  if (cd < 0.0) { col = vec4f(mix(vec3f(0.99, 0.95, 0.9), vec3f(0.9, 0.7, 0.8), clamp(-cd * 4.0, 0.0, 1.0)), 1.0); }
  return col;
}

fn visual_orchid(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let sway = uni(0);
  let gust = uni(1);
  let mc = vec2f(uni(2), uni(3));
  let breeze = uni(4);

  // ── the greenhouse: warm depth, soft bokeh lights, falling dust of pollen ──
  var col = mix(vec3f(0.055, 0.075, 0.055), vec3f(0.10, 0.13, 0.10), 0.5 - 0.5 * uv.y);
  col += vec3f(0.16, 0.15, 0.10) * smoothstep(0.9, 0.0, length(uv - vec2f(-0.55, -0.55))) * 0.5;
  for (var b = 0; b < 3; b++) {
    let fb = f32(b);
    let bc = vec2f(sin(fb * 2.7) * 0.7, -0.3 + fb * 0.28);
    col += vec3f(0.10, 0.11, 0.07) * exp(-dot(uv - bc, uv - bc) * (7.0 + fb * 4.0));
  }
  let pm = vec2f(uv.x * 8.0 + sin(t * 0.3 + uv.y * 3.0) * 0.3, uv.y * 8.0 + t * 0.06);
  let ph = hash21(floor(pm));
  col += vec3f(0.55, 0.5, 0.35) * step(0.985, ph) * smoothstep(0.3, 0.05, length(fract(pm) - 0.5)) * 0.25;

  // ── the sway: wind + your breath, bending more with height ──
  let hgt = clamp((0.55 - uv.y) / 1.1, 0.0, 1.0);
  let bend = (sway * 0.5 + gust * 0.9 + breeze * 0.9) * 0.14;
  // work in plant coords: unbend the world instead of bending the plant
  var pp = uv - vec2f(-0.05, 0.62);
  pp = rotate(pp, -bend * hgt * hgt * 2.2);

  // ── leaves at the root: broad, glossy, veined ──
  for (var lf = 0; lf < 3; lf++) {
    let f2 = f32(lf);
    let la = -0.9 + f2 * 0.85 + sin(t * 0.6 + f2) * 0.015;
    let ld2 = orc_ell(pp, vec2f(cos(la) * 0.34, -0.02 + abs(sin(la)) * 0.05), vec2f(0.36, 0.13), la * 0.55);
    if (ld2 < 0.0) {
      var lc2 = mix(vec3f(0.05, 0.20, 0.08), vec3f(0.13, 0.38, 0.15), clamp(-ld2 * 2.0, 0.0, 1.0));
      let mid = abs(sin(atan2(pp.y + 0.02, pp.x - cos(la) * 0.34) - la * 0.55));
      lc2 += vec3f(0.10, 0.16, 0.10) * pow(1.0 - mid, 6.0) * 0.5;       // center vein gloss
      lc2 *= 0.85 + 0.3 * clamp(-(pp.x + pp.y), 0.0, 1.0);
      col = mix(col, lc2, smoothstep(0.01, -0.02, ld2));
    }
  }

  // ── the stem: one clean arc climbing to the blooms ──
  {
    let sx = pow(clamp(-pp.y / 1.05, 0.0, 1.0), 1.7) * 0.34
      + sin(pp.y * 2.2 + t * 0.7) * 0.004;
    let sd = abs(pp.x - sx) - (0.016 - clamp(-pp.y, 0.0, 1.0) * 0.008);
    if (pp.y < 0.05 && pp.y > -1.12 && sd < 0.0) {
      var sc = mix(vec3f(0.16, 0.34, 0.12), vec3f(0.30, 0.5, 0.2), clamp(-sd * 30.0, 0.0, 1.0));
      sc *= 0.8 + 0.4 * clamp(-pp.x + sx + 0.01, 0.0, 1.0) * 30.0 * 0.03;
      col = mix(col, sc, smoothstep(0.004, -0.004, sd));
    }
  }

  // ── the blooms: four faces along the arc, each swaying on its own pedicel ──
  for (var k = 0; k < 4; k++) {
    let fk = f32(k);
    let by = -0.42 - fk * 0.235;
    let bx = pow(clamp(-by / 1.05, 0.0, 1.0), 1.7) * 0.34 + 0.10 + sin(fk * 2.1) * 0.05;
    let bs = 0.155 - fk * 0.012;
    let flut = 0.4 + gust * 1.2 + breeze * 0.8;
    let bp = rotate(pp - vec2f(bx, by), sin(t * (0.9 + fk * 0.13) + fk * 1.7) * 0.05 * flut + bend * 0.6);
    let bloom = orc_bloom(bp, bs, flut, fk * 3.7 + 1.0);
    col = mix(col, bloom.rgb, bloom.a);
  }
  // two buds at the tip, jade teardrops blushing at the seam
  for (var bu = 0; bu < 2; bu++) {
    let fb2 = f32(bu);
    let by2 = -1.02 - fb2 * 0.09;
    let bx2 = pow(clamp(-by2 / 1.05, 0.0, 1.0), 1.7) * 0.34 + 0.045 + fb2 * 0.03;
    let bd = orc_ell(pp, vec2f(bx2, by2), vec2f(0.030 - fb2 * 0.008, 0.045 - fb2 * 0.010), 0.4);
    if (bd < 0.0) {
      var bc2 = mix(vec3f(0.30, 0.45, 0.22), vec3f(0.55, 0.60, 0.35), clamp(-bd * 5.0, 0.0, 1.0));
      bc2 = mix(bc2, vec3f(0.85, 0.5, 0.65), smoothstep(0.02, 0.0, abs(pp.x - bx2)) * 0.4);
      col = mix(col, bc2, smoothstep(0.006, -0.006, bd));
    }
  }

  // your breath: the faintest shimmer where the air moves
  col += vec3f(0.5, 0.55, 0.45) * exp(-dot(uv - mc, uv - mc) * 500.0) * breeze * 0.12;

  col *= 1.0 - 0.35 * pow(length(uv) * 0.75, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.05); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}
